  5	import {
  6	  Chart,
  7	  ChartAxis,
  8	  ChartAxisProps,
  9	  ChartDonut,
 10	  ChartGroup,
 11	  ChartLabel,
 12	  ChartLegend,
 13	  ChartLine,
 14	  ChartVoronoiContainer,
 15	} from '@patternfly/react-charts';
 16	import {
 17	  Alert,
 18	  Card,
 19	  CardBody,
 20	  CardTitle,
 21	  Grid,
 22	  GridItem,
 23	  Popover,
 24	} from '@patternfly/react-core';
 25	import { chart_color_black_200 as othersColor } from '@patternfly/react-tokens/dist/js/chart_color_black_200';
 26	import { chart_color_black_500 as cancelledColor } from '@patternfly/react-tokens/dist/js/chart_color_black_500';
 27	import { chart_color_green_400 as successColor } from '@patternfly/react-tokens/dist/js/chart_color_green_400';
 28	import { t_global_color_status_danger_default as failureColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 29	import { chart_color_blue_300 as runningColor } from '@patternfly/react-tokens/dist/js/chart_color_blue_300';
 30	import {
 31	  formatDate,
 32	  getXaxisValues,
 33	  hourformat,
 34	  parsePrometheusDuration,
 35	  monthYear,
 36	} from './dateTime';
 37	import './PipelinesOverview.scss';
 38	import { ALL_NAMESPACES_KEY } from '../../consts';
 39	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
 40	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 41	import {
 42	  usePipelineMetricsForAllNamespacePoll,
 43	  usePipelineMetricsForNamespacePoll,
 44	  usePipelineMetricsForNamespaceForPipelinePoll,
 45	} from '../pipelines-metrics/hooks';
 46	import {
 47	  MetricsQueryPrefix,
 48	  PipelineQuery,
 49	  adjustToStartOfWeek,
 50	} from '../pipelines-metrics/utils';
 51	import { getTotalPipelineRuns, isMatchingFirstTickValue } from './utils';
 52	import { LoadingInline } from '../Loading';
 53	
 54	interface PipelinesRunsStatusCardProps {
 55	  timespan?: number;
 56	  domain?: DomainPropType;
 57	  bordered?: boolean;
 58	  namespace: string;
 59	  interval: number;
 60	  parentName?: string;
 61	}
 62	
 63	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 64	
 65	const getStatusSummary = (promQueryToSummaryResponse) => {
 66	  const result = {
 67	    cancelled: 0,
 68	    failed: 0,
 69	    succeeded: 0,
 70	    total: 0,
 71	  };
 72	  promQueryToSummaryResponse?.forEach((item) => {
 73	    result.cancelled += item.cancelled;
 74	    result.failed += item.failed;
 75	    result.succeeded += item.succeeded;
 76	    result.total = result.cancelled + result.failed + result.succeeded;
 77	  });
 78	
 79	  return result;
 80	};
 81	
 82	export const getChartDataK8s = (
 83	  tickValues: number[] | Date[],
 84	  data: any,
 85	  key: string,
 86	  type: string,
 87	): {
 88	  x: number;
 89	  y: number;
 90	  name: string;
 91	}[] => {
 92	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 93	  const k = key.toLowerCase();
 94	  const sortedTickValues = tickValues.slice().sort((a, b) => a - b);
 95	  const chartData = sortedTickValues?.map((value, index) => {
 96	    if (index === 0) {
 97	      // Ensure the first value is always 0
 98	      return {
 99	        x: value,
100	        y: 0,
101	        name: t(key),
102	      };
103	    }
104	    const s = data?.find((d) => {
105	      const group_date = new Date(Number(d.group_value) * 1000);
106	      if (type == 'hour') {
107	        return group_date.getHours() === value;
108	      }
109	      if (type == 'week') {
110	        const adjustedGroupDate = adjustToStartOfWeek(new Date(group_date));
111	        return (
112	          adjustedGroupDate.toDateString() === new Date(value).toDateString()
113	        );
114	      }
115	      if (type == 'day') {
116	        return group_date.toDateString() === new Date(value).toDateString();
117	      }
118	      if (type == 'month') {
119	        return group_date.getMonth() === value.getMonth();
120	      }
121	    });
122	    return {
123	      x: value,
124	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
125	      name: t(key),
126	    };
127	  });
128	  return chartData;
129	};
130	
131	export const getIncrementedValues = (
132	  data,
133	  tickValues: number[] | Date[],
134	  type: string,
135	) => {
136	  const originalData = JSON.parse(JSON.stringify(data));
137	  for (let i = 1; i < data.length; i++) {
138	    const prevCancelled = originalData[i - 1].cancelled;
139	    const currentCancelled = originalData[i].cancelled;
140	    data[i].cancelled =
141	      currentCancelled >= prevCancelled
142	        ? currentCancelled - prevCancelled
143	        : currentCancelled;
144	
145	    const prevFailed = originalData[i - 1].failed;
146	    const currentFailed = originalData[i].failed;
147	    data[i].failed =
148	      currentFailed >= prevFailed ? currentFailed - prevFailed : currentFailed;
149	
150	    const prevSucceeded = originalData[i - 1].succeeded;
151	    const currentSucceeded = originalData[i].succeeded;
152	    data[i].succeeded =
153	      currentSucceeded >= prevSucceeded
154	        ? currentSucceeded - prevSucceeded
155	        : currentSucceeded;
156	  }
157	
158	  const firstTickValue = tickValues[0];
159	  data.forEach((item) => {
160	    item.total = item.cancelled + item.failed + item.succeeded;
161	    const isMatch = isMatchingFirstTickValue(
162	      firstTickValue,
163	      item.group_value,
164	      type,
165	    );
166	    if (isMatch) {
167	      data[0].cancelled = 0;
168	      data[0].failed = 0;
169	      data[0].succeeded = 0;
170	    }
171	  });
172	
173	  return data;
174	};
175	
176	const transformPrometheusResultToSummary = (
177	  prometheusResult: PrometheusResponse,
178	  tickValues: number[] | Date[],
179	  type: string,
180	) => {
181	  const summary = [];
182	  if (
183	    prometheusResult &&
184	    prometheusResult.data &&
185	    prometheusResult.data.result
186	  ) {
187	    prometheusResult.data.result.forEach((metric) => {
188	      metric.values.forEach((value) => {
189	        const groupValue = value[0];
190	
191	        let summaryObj = summary.find((obj) => obj.group_value === groupValue);
192	
193	        if (!summaryObj) {
194	          summaryObj = {
195	            group_value: groupValue,
196	            cancelled: 0,
197	            failed: 0,
198	            succeeded: 0,
199	          };
200	          summary.push(summaryObj);
201	        }
202	
203	        switch (metric.metric.status) {
204	          case 'cancelled':
205	            summaryObj.cancelled = parseInt(value[1], 10);
206	            break;
207	          case 'failed':
208	            summaryObj.failed = parseInt(value[1], 10);
209	            break;
210	          case 'success':
211	            summaryObj.succeeded = parseInt(value[1], 10);
212	            break;
213	          default:
214	            break;
215	        }
216	      });
217	    });
218	  }
219	  summary.sort((a, b) => a.group_value - b.group_value);
220	  const finalResult = getIncrementedValues(summary, tickValues, type);
221	  return finalResult;
222	};
223	
224	const PipelineRunsStatusCardK8s: React.FC<PipelinesRunsStatusCardProps> = ({
225	  timespan,
226	  domain,
227	  bordered,
228	  namespace,
229	  interval,
230	  parentName,
231	}) => {
232	  const { t } = useTranslation('plugin__pipelines-console-plugin');
233	  const startTimespan = timespan - parsePrometheusDuration('1d');
234	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
235	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
236	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
237	  const domainValue: DomainPropType = {
238	    x: domainX || [startDate, endDate],
239	    y: domainY || undefined,
240	  };
241	  const [pipelineRunsStatusError, setPipelineRunsStatusError] = React.useState<
242	    string | null
243	  >(null);
244	  const [
245	    runSuccessRatioData,
246	    runSuccessRatioError,
247	    loadingRunSuccessRatioData,
248	  ] =
249	    parentName && namespace
250	      ? usePipelineMetricsForNamespaceForPipelinePoll({
251	          namespace,
252	          timespan,
253	          delay: interval,
254	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
255	          name: parentName,
256	          metricsQuery:
257	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_NAMESPACE_FOR_PIPELINE,
258	          timeout: 90000,
259	        })
260	      : namespace == ALL_NAMESPACES_KEY
261	      ? usePipelineMetricsForAllNamespacePoll({
262	          timespan,
263	          delay: interval,
264	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
265	          metricsQuery:
266	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_ALL_NAMESPACE,
267	          timeout: 90000,
268	        })
269	      : usePipelineMetricsForNamespacePoll({
270	          namespace,
271	          timespan,
272	          delay: interval,
273	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
274	          metricsQuery:
275	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_NAMESPACE,
276	          timeout: 90000,
277	        });
278	  const [
279	    totalPipelineRunsData,
280	    totalPipelineRunsError,
281	    loadingTotalPipelineRunsData,
282	  ] =
283	    parentName && namespace
284	      ? usePipelineMetricsForNamespaceForPipelinePoll({
285	          namespace,
286	          timespan,
287	          delay: interval,
288	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
289	          name: parentName,
290	          metricsQuery:
291	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
292	          timeout: 90000,
293	        })
294	      : namespace == ALL_NAMESPACES_KEY
295	      ? usePipelineMetricsForAllNamespacePoll({
296	          timespan,
297	          delay: interval,
298	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
299	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
300	          timeout: 90000,
301	        })
302	      : usePipelineMetricsForNamespacePoll({
303	          namespace,
304	          timespan,
305	          delay: interval,
306	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
307	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
308	          timeout: 90000,
309	        });
310	
311	  const [tickValues, type] = getXaxisValues(timespan);
312	
313	  const totalPipelineRuns = React.useMemo(() => {
314	    if (totalPipelineRunsError) {
315	      return [];
316	    }
317	    return getTotalPipelineRuns(totalPipelineRunsData, tickValues, type);
318	  }, [totalPipelineRunsData, tickValues, type, totalPipelineRunsError]);
319	
320	  const promQueryToSummaryResponse = React.useMemo(() => {
321	    if (runSuccessRatioError) {
322	      return [];
323	    }
324	    return transformPrometheusResultToSummary(
325	      runSuccessRatioData,
326	      tickValues,
327	      type,
328	    );
329	  }, [runSuccessRatioData, tickValues, type, runSuccessRatioError]);
330	
331	  let xTickFormat;
332	  let dayLabel;
333	  let showLabel = false;
334	  let chartDataSucceededK8s = [];
335	  let chartDataFailedK8s = [];
336	  let chartDataCancelledK8s = [];
337	  switch (type) {
338	    case 'hour':
339	      xTickFormat = (d) => hourformat(d);
340	      showLabel = true;
341	      domainValue.x = [0, 23];
342	
343	      dayLabel = formatDate(new Date());
344	
345	      chartDataCancelledK8s = getChartDataK8s(
346	        tickValues,
347	        promQueryToSummaryResponse,
348	        'Cancelled',
349	        'hour',
350	      );
351	      chartDataSucceededK8s = getChartDataK8s(
352	        tickValues,
353	        promQueryToSummaryResponse,
354	        'Succeeded',
355	        'hour',
356	      );
357	      chartDataFailedK8s = getChartDataK8s(
358	        tickValues,
359	        promQueryToSummaryResponse,
360	        'Failed',
361	        'hour',
362	      );
363	      break;
364	    case 'day':
365	      xTickFormat = (d) => formatDate(d);
366	      domainValue.x = [startDate, endDate];
367	
368	      chartDataCancelledK8s = getChartDataK8s(
369	        tickValues,
370	        promQueryToSummaryResponse,
371	        'Cancelled',
372	        'day',
373	      );
374	      chartDataSucceededK8s = getChartDataK8s(
375	        tickValues,
376	        promQueryToSummaryResponse,
377	        'Succeeded',
378	        'day',
379	      );
380	      chartDataFailedK8s = getChartDataK8s(
381	        tickValues,
382	        promQueryToSummaryResponse,
383	        'Failed',
384	        'day',
385	      );
386	
387	      break;
388	    case 'week':
389	      xTickFormat = (d) => formatDate(d);
390	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
391	
392	      chartDataCancelledK8s = getChartDataK8s(
393	        tickValues,
394	        promQueryToSummaryResponse,
395	        'Cancelled',
396	        'week',
397	      );
398	      chartDataSucceededK8s = getChartDataK8s(
399	        tickValues,
400	        promQueryToSummaryResponse,
401	        'Succeeded',
402	        'week',
403	      );
404	      chartDataFailedK8s = getChartDataK8s(
405	        tickValues,
406	        promQueryToSummaryResponse,
407	        'Failed',
408	        'week',
409	      );
410	
411	      break;
412	    case 'month':
413	      xTickFormat = (d) => monthYear(d);
414	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
415	
416	      chartDataCancelledK8s = getChartDataK8s(
417	        tickValues,
418	        promQueryToSummaryResponse,
419	        'Cancelled',
420	        'month',
421	      );
422	      chartDataSucceededK8s = getChartDataK8s(
423	        tickValues,
424	        promQueryToSummaryResponse,
425	        'Succeeded',
426	        'month',
427	      );
428	      chartDataFailedK8s = getChartDataK8s(
429	        tickValues,
430	        promQueryToSummaryResponse,
431	        'Failed',
432	        'month',
433	      );
434	
435	      break;
436	    default:
437	      console.log('Received wrong data');
438	      break;
439	  }
440	
441	  let xAxisStyle: ChartAxisProps['style'] = {
442	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
443	  };
444	  const yAxisStyle: ChartAxisProps['style'] = {
445	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
446	  };
447	  if (tickValues?.length > 7) {
448	    xAxisStyle = {
449	      tickLabels: {
450	        fill: 'var(--pf-t--global--text--color--regular)',
451	        angle: 320,
452	        fontSize: 10,
453	        textAnchor: 'end',
454	        verticalAnchor: 'end',
455	      },
456	    };
457	  }
458	
459	  const colorScale = [
460	    successColor.value,
461	    failureColor.value,
462	    runningColor.value,
463	    cancelledColor.value,
464	    othersColor.value,
465	  ];
466	
467	  const colorScaleLineChart = [
468	    successColor.value,
469	    failureColor.value,
470	    cancelledColor.value,
471	    othersColor.value,
472	  ];
473	
474	  const donutDataObjK8s = React.useMemo(() => {
475	    if (totalPipelineRunsError || runSuccessRatioError) {
476	      return;
477	    }
478	    return getStatusSummary(promQueryToSummaryResponse);
479	  }, [
480	    promQueryToSummaryResponse,
481	    totalPipelineRunsError,
482	    runSuccessRatioError,
483	  ]);
484	
485	  const donutDataK8s = [
486	    {
487	      x: t('Succeeded'),
488	      y: Math.round(
489	        (100 * donutDataObjK8s?.succeeded) / donutDataObjK8s?.total,
490	      ),
491	    },
492	    {
493	      x: t('Failed'),
494	      y: Math.round((100 * donutDataObjK8s?.failed) / donutDataObjK8s?.total),
495	    },
496	
497	    {
498	      x: t('Cancelled'),
499	      y: Math.round(
500	        (100 * donutDataObjK8s?.cancelled) / donutDataObjK8s?.total,
501	      ),
502	    },
503	  ];
504	
505	  const legendData = donutDataK8s.map((data) => {
506	    return {
507	      name: `${data.x}: ${isNaN(data.y) ? 0 : data.y}%`,
508	    };
509	  });
510	
511	  React.useEffect(() => {
512	    const hasNonAbortError =
513	      (runSuccessRatioError && runSuccessRatioError.name !== 'AbortError') ||
514	      (totalPipelineRunsError && totalPipelineRunsError.name !== 'AbortError');
515	    setPipelineRunsStatusError(
516	      hasNonAbortError
517	        ? runSuccessRatioError?.message ??
518	            totalPipelineRunsError?.message ??
519	            t('Unable to load PipelineRun status')
520	        : null,
521	    );
522	  }, [runSuccessRatioError, totalPipelineRunsError]);
523	
524	  return (
525	    <>
526	      <Card
527	        className={classNames('pipeline-overview__pipelinerun-status-card', {
528	          'card-border': bordered,
529	        })}
530	      >
531	        <CardTitle className="pipeline-overview__pipelinerun-status-card__title">
532	          <span>
533	            {t('PipelineRun status')}{' '}
534	            <Popover
535	              bodyContent={
536	                <>
537	                  {t(
538	                    'PipelineRun status shows the % of PipelineRuns for various statuses like "Succeeded", "Failed" and "Cancelled".',
539	                  )}
540	                </>
541	              }
542	            >
543	              <span
544	                role="button"
545	                aria-label={t('More info')}
546	                className="ocs-getting-started-grid__tooltip-icon"
547	              >
548	                <OutlinedQuestionCircleIcon />
549	              </span>
550	            </Popover>
551	          </span>
552	        </CardTitle>
553	        <CardBody className="pipeline-overview__pipelinerun-status-card__title">
554	          {pipelineRunsStatusError ? (
555	            <Alert
556	              variant="danger"
557	              isInline
558	              title={t('Unable to load PipelineRun status')}
559	              className="pf-v6-u-mb-md"
560	            />
561	          ) : (
562	            <Grid>
563	              <GridItem xl2={4} xl={12} lg={12} md={12} sm={12}>
564	                {loadingRunSuccessRatioData ? (
565	                  <LoadingInline />
566	                ) : (
567	                  <div className="pipeline-overview__pipelinerun-status-card__donut-chart-div">
568	                    <ChartDonut
569	                      constrainToVisibleArea={true}
570	                      data={donutDataK8s}
571	                      labels={({ datum }) => `${datum.x}: ${datum.y}%`}
572	                      legendData={legendData}
573	                      colorScale={colorScale}
574	                      legendOrientation="vertical"
575	                      legendPosition="right"
576	                      padding={{
577	                        bottom: 30,
578	                        right: 140, // Adjusted to accommodate legend
579	                        top: 20,
580	                      }}
581	                      legendComponent={
582	                        <ChartLegend
583	                          data={legendData}
584	                          style={{
585	                            labels: {
586	                              fill: 'var(--pf-t--global--text--color--regular)',
587	                              fontSize: 14,
588	                            },
589	                          }}
590	                        />
591	                      }
592	                      subTitle={t('Succeeded')}
593	                      subTitleComponent={
594	                        <ChartLabel
595	                          style={{
596	                            fill: 'var(--pf-t--global--text--color--400)',
597	                            fontSize: 14,
598	                          }}
599	                        />
600	                      }
601	                      title={
602	                        typeof donutDataObjK8s !== 'undefined'
603	                          ? `${donutDataObjK8s?.succeeded}/${totalPipelineRuns}`
604	                          : ''
605	                      }
606	                      titleComponent={
607	                        <ChartLabel
608	                          style={{
609	                            fill: 'var(--pf-t--global--text--color--regular)',
610	                            fontSize: 24,
611	                          }}
612	                        />
613	                      }
614	                      width={350}
615	                    />
616	                  </div>
617	                )}
618	              </GridItem>
619	              <GridItem xl2={8} xl={12} lg={12} md={12} sm={12}>
620	                <div className="pipeline-overview__pipelinerun-status-card__bar-chart-div">
621	                  {loadingTotalPipelineRunsData ? (
622	                    <LoadingInline />
623	                  ) : (
624	                    <Chart
625	                      containerComponent={
626	                        <ChartVoronoiContainer
627	                          labels={({ datum }) => `${datum.name}: ${datum.y}%`}
628	                          constrainToVisibleArea
629	                        />
630	                      }
631	                      scale={{ x: 'time', y: 'linear' }}
632	                      domain={domainValue}
633	                      domainPadding={{ x: [30, 25] }}
634	                      height={200}
635	                      padding={{
636	                        top: 20,
637	                        bottom: 40,
638	                        right: 40,
639	                        left: 50,
640	                      }}
641	                      colorScale={colorScaleLineChart}
642	                      width={1000}
643	                    >
644	                      <ChartAxis
645	                        tickValues={tickValues}
646	                        style={xAxisStyle}
647	                        tickFormat={xTickFormat}
648	                        label={showLabel ? dayLabel : ''}
649	                      />
650	                      <ChartAxis
651	                        dependentAxis
652	                        tickFormat={(v) => `${v}%`}
653	                        style={yAxisStyle}
654	                      />
655	                      <ChartGroup>
656	                        <ChartLine data={chartDataSucceededK8s} />
657	                        <ChartLine data={chartDataFailedK8s} />
658	                        <ChartLine data={chartDataCancelledK8s} />
659	                      </ChartGroup>
660	                    </Chart>
661	                  )}
662	                </div>
663	              </GridItem>
664	            </Grid>
665	          )}
666	        </CardBody>
667	      </Card>
668	    </>
669	  );
670	};
671	
672	export default PipelineRunsStatusCardK8s;

