 65	const getStatusSummary = (promQueryToSummaryResponse) => {
 66	  const result = {
 67	    cancelled: 0,
 68	    failed: 0,
 69	    succeeded: 0,
 70	    total: 0,
 71	  };
 72	  promQueryToSummaryResponse?.forEach((item) => {
 73	    result.cancelled += item.cancelled;
 74	    result.failed += item.failed;
 75	    result.succeeded += item.succeeded;
 76	    result.total = result.cancelled + result.failed + result.succeeded;
 77	  });
 78	
 79	  return result;
 80	};
