 81	export const getChartDataK8s = (
 82	  tickValues: number[] | Date[],
 83	  data: any,
 84	  key: string,
 85	  type: string,
 86	): {
 87	  x: number;
 88	  y: number;
 89	  name: string;
 90	}[] => {
 91	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 92	  const k = key.toLowerCase();
 93	  const sortedTickValues = tickValues.slice().sort((a, b) => a - b);
 94	  const chartData = sortedTickValues?.map((value, index) => {
 95	    if (index === 0) {
 96	      // Ensure the first value is always 0
 97	      return {
 98	        x: value,
 99	        y: 0,
100	        name: t(key),
101	      };
102	    }
103	    const s = data?.find((d) => {
104	      const group_date = new Date(Number(d.group_value) * 1000);
105	      if (type == 'hour') {
106	        return group_date.getHours() === value;
107	      }
108	      if (type == 'week') {
109	        const adjustedGroupDate = adjustToStartOfWeek(new Date(group_date));
110	        return (
111	          adjustedGroupDate.toDateString() === new Date(value).toDateString()
112	        );
113	      }
114	      if (type == 'day') {
115	        return group_date.toDateString() === new Date(value).toDateString();
116	      }
117	      if (type == 'month') {
118	        return group_date.getMonth() === value.getMonth();
119	      }
120	    });
121	    return {
122	      x: value,
123	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
124	      name: t(key),
125	    };
126	  });
127	  return chartData;
128	};
