175	const transformPrometheusResultToSummary = (
176	  prometheusResult: PrometheusResponse,
177	  tickValues: number[] | Date[],
178	  type: string,
179	) => {
180	  const summary = [];
181	  if (
182	    prometheusResult &&
183	    prometheusResult.data &&
184	    prometheusResult.data.result
185	  ) {
186	    prometheusResult.data.result.forEach((metric) => {
187	      metric.values.forEach((value) => {
188	        const groupValue = value[0];
189	
190	        let summaryObj = summary.find((obj) => obj.group_value === groupValue);
191	
192	        if (!summaryObj) {
193	          summaryObj = {
194	            group_value: groupValue,
195	            cancelled: 0,
196	            failed: 0,
197	            succeeded: 0,
198	          };
199	          summary.push(summaryObj);
200	        }
201	
202	        switch (metric.metric.status) {
203	          case 'cancelled':
204	            summaryObj.cancelled = parseInt(value[1], 10);
205	            break;
206	          case 'failed':
207	            summaryObj.failed = parseInt(value[1], 10);
208	            break;
209	          case 'success':
210	            summaryObj.succeeded = parseInt(value[1], 10);
211	            break;
212	          default:
213	            break;
214	        }
215	      });
216	    });
217	  }
218	  summary.sort((a, b) => a.group_value - b.group_value);
219	  const finalResult = getIncrementedValues(summary, tickValues, type);
220	  return finalResult;
221	};
