 39	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 40	import {
 41	  usePipelineMetricsForAllNamespacePoll,
 42	  usePipelineMetricsForNamespacePoll,
 43	  usePipelineMetricsForNamespaceForPipelinePoll,
 44	} from '../pipelines-metrics/hooks';
 45	import {
 46	  MetricsQueryPrefix,
 47	  PipelineQuery,
 48	  adjustToStartOfWeek,
 49	} from '../pipelines-metrics/utils';
 50	import { getTotalPipelineRuns, isMatchingFirstTickValue } from './utils';
 51	import { LoadingInline } from '../Loading';
 52	
 53	interface PipelinesRunsStatusCardProps {
 54	  timespan?: number;
 55	  domain?: DomainPropType;
 56	  bordered?: boolean;
 57	  namespace: string;
 58	  interval: number;
 59	  parentName?: string;
 60	}
 61	
 62	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 63	
 64	const getStatusSummary = (promQueryToSummaryResponse) => {
 65	  const result = {
 66	    cancelled: 0,
 67	    failed: 0,
 68	    succeeded: 0,
 69	    total: 0,
 70	  };
 71	  promQueryToSummaryResponse?.forEach((item) => {
 72	    result.cancelled += item.cancelled;
 73	    result.failed += item.failed;
 74	    result.succeeded += item.succeeded;
 75	    result.total = result.cancelled + result.failed + result.succeeded;
 76	  });
 77	
 78	  return result;
 79	};
 80	
 81	export const getChartDataK8s = (
 82	  tickValues: number[] | Date[],
 83	  data: any,
 84	  key: string,
 85	  type: string,
 86	): {
 87	  x: number;
 88	  y: number;
 89	  name: string;
 90	}[] => {
 91	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 92	  const k = key.toLowerCase();
 93	  const sortedTickValues = tickValues.slice().sort((a, b) => a - b);
 94	  const chartData = sortedTickValues?.map((value, index) => {
 95	    if (index === 0) {
 96	      // Ensure the first value is always 0
 97	      return {
 98	        x: value,
 99	        y: 0,
100	        name: t(key),
101	      };
102	    }
103	    const s = data?.find((d) => {
104	      const group_date = new Date(Number(d.group_value) * 1000);
105	      if (type == 'hour') {
106	        return group_date.getHours() === value;
107	      }
108	      if (type == 'week') {
109	        const adjustedGroupDate = adjustToStartOfWeek(new Date(group_date));
110	        return (
111	          adjustedGroupDate.toDateString() === new Date(value).toDateString()
112	        );
113	      }
114	      if (type == 'day') {
115	        return group_date.toDateString() === new Date(value).toDateString();
116	      }
117	      if (type == 'month') {
118	        return group_date.getMonth() === value.getMonth();
119	      }
120	    });
121	    return {
122	      x: value,
123	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
124	      name: t(key),
125	    };
126	  });
127	  return chartData;
128	};
129	
130	export const getIncrementedValues = (
131	  data,
132	  tickValues: number[] | Date[],
133	  type: string,
134	) => {
135	  const originalData = JSON.parse(JSON.stringify(data));
136	  for (let i = 1; i < data.length; i++) {
137	    const prevCancelled = originalData[i - 1].cancelled;
138	    const currentCancelled = originalData[i].cancelled;
139	    data[i].cancelled =
140	      currentCancelled >= prevCancelled
141	        ? currentCancelled - prevCancelled
142	        : currentCancelled;
143	
144	    const prevFailed = originalData[i - 1].failed;
145	    const currentFailed = originalData[i].failed;
146	    data[i].failed =
147	      currentFailed >= prevFailed ? currentFailed - prevFailed : currentFailed;
148	
149	    const prevSucceeded = originalData[i - 1].succeeded;
150	    const currentSucceeded = originalData[i].succeeded;
151	    data[i].succeeded =
152	      currentSucceeded >= prevSucceeded
153	        ? currentSucceeded - prevSucceeded
154	        : currentSucceeded;
155	  }
156	
157	  const firstTickValue = tickValues[0];
158	  data.forEach((item) => {
159	    item.total = item.cancelled + item.failed + item.succeeded;
160	    const isMatch = isMatchingFirstTickValue(
161	      firstTickValue,
162	      item.group_value,
163	      type,
164	    );
165	    if (isMatch) {
166	      data[0].cancelled = 0;
167	      data[0].failed = 0;
168	      data[0].succeeded = 0;
169	    }
170	  });
171	
172	  return data;
173	};
174	
175	const transformPrometheusResultToSummary = (
176	  prometheusResult: PrometheusResponse,
177	  tickValues: number[] | Date[],
178	  type: string,
179	) => {
180	  const summary = [];
181	  if (
182	    prometheusResult &&
183	    prometheusResult.data &&
184	    prometheusResult.data.result
185	  ) {
186	    prometheusResult.data.result.forEach((metric) => {
187	      metric.values.forEach((value) => {
188	        const groupValue = value[0];
189	
190	        let summaryObj = summary.find((obj) => obj.group_value === groupValue);
191	
192	        if (!summaryObj) {
193	          summaryObj = {
194	            group_value: groupValue,
195	            cancelled: 0,
196	            failed: 0,
197	            succeeded: 0,
198	          };
199	          summary.push(summaryObj);
200	        }
201	
202	        switch (metric.metric.status) {
203	          case 'cancelled':
204	            summaryObj.cancelled = parseInt(value[1], 10);
205	            break;
206	          case 'failed':
207	            summaryObj.failed = parseInt(value[1], 10);
208	            break;
209	          case 'success':
210	            summaryObj.succeeded = parseInt(value[1], 10);
211	            break;
212	          default:
213	            break;
214	        }
215	      });
216	    });
217	  }
218	  summary.sort((a, b) => a.group_value - b.group_value);
219	  const finalResult = getIncrementedValues(summary, tickValues, type);
220	  return finalResult;
221	};
