223	const PipelineRunsStatusCardK8s: React.FC<PipelinesRunsStatusCardProps> = ({
224	  timespan,
225	  domain,
226	  bordered,
227	  namespace,
228	  interval,
229	  parentName,
230	}) => {
231	  const { t } = useTranslation('plugin__pipelines-console-plugin');
232	  const startTimespan = timespan - parsePrometheusDuration('1d');
233	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
234	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
235	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
236	  const domainValue: DomainPropType = {
237	    x: domainX || [startDate, endDate],
238	    y: domainY || undefined,
239	  };
240	  const [pipelineRunsStatusError, setPipelineRunsStatusError] = React.useState<
241	    string | null
242	  >(null);
243	  const [
244	    runSuccessRatioData,
245	    runSuccessRatioError,
246	    loadingRunSuccessRatioData,
247	  ] =
248	    parentName && namespace
249	      ? usePipelineMetricsForNamespaceForPipelinePoll({
250	          namespace,
251	          timespan,
252	          delay: interval,
253	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
254	          name: parentName,
255	          metricsQuery:
256	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_NAMESPACE_FOR_PIPELINE,
257	          timeout: 90000,
258	        })
259	      : namespace == ALL_NAMESPACES_KEY
260	      ? usePipelineMetricsForAllNamespacePoll({
261	          timespan,
262	          delay: interval,
263	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
264	          metricsQuery:
265	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_ALL_NAMESPACE,
266	          timeout: 90000,
267	        })
268	      : usePipelineMetricsForNamespacePoll({
269	          namespace,
270	          timespan,
271	          delay: interval,
272	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
273	          metricsQuery:
274	            PipelineQuery.PIPELINERUN_COUNT_FOR_STATUS_FOR_NAMESPACE,
275	          timeout: 90000,
276	        });
277	  const [
278	    totalPipelineRunsData,
279	    totalPipelineRunsError,
280	    loadingTotalPipelineRunsData,
281	  ] =
282	    parentName && namespace
283	      ? usePipelineMetricsForNamespaceForPipelinePoll({
284	          namespace,
285	          timespan,
286	          delay: interval,
287	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
288	          name: parentName,
289	          metricsQuery:
290	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
291	          timeout: 90000,
292	        })
293	      : namespace == ALL_NAMESPACES_KEY
294	      ? usePipelineMetricsForAllNamespacePoll({
295	          timespan,
296	          delay: interval,
297	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
298	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
299	          timeout: 90000,
300	        })
301	      : usePipelineMetricsForNamespacePoll({
302	          namespace,
303	          timespan,
304	          delay: interval,
305	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
306	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
307	          timeout: 90000,
308	        });
309	
310	  const [tickValues, type] = getXaxisValues(timespan);
311	
312	  const totalPipelineRuns = React.useMemo(() => {
313	    if (totalPipelineRunsError) {
314	      return [];
315	    }
316	    return getTotalPipelineRuns(totalPipelineRunsData, tickValues, type);
317	  }, [totalPipelineRunsData, tickValues, type, totalPipelineRunsError]);
318	
319	  const promQueryToSummaryResponse = React.useMemo(() => {
320	    if (runSuccessRatioError) {
321	      return [];
322	    }
323	    return transformPrometheusResultToSummary(
324	      runSuccessRatioData,
325	      tickValues,
326	      type,
327	    );
328	  }, [runSuccessRatioData, tickValues, type, runSuccessRatioError]);
329	
330	  let xTickFormat;
331	  let dayLabel;
332	  let showLabel = false;
333	  let chartDataSucceededK8s = [];
334	  let chartDataFailedK8s = [];
335	  let chartDataCancelledK8s = [];
336	  switch (type) {
337	    case 'hour':
338	      xTickFormat = (d) => hourformat(d);
339	      showLabel = true;
340	      domainValue.x = [0, 23];
341	
342	      dayLabel = formatDate(new Date());
343	
344	      chartDataCancelledK8s = getChartDataK8s(
345	        tickValues,
346	        promQueryToSummaryResponse,
347	        'Cancelled',
348	        'hour',
349	      );
350	      chartDataSucceededK8s = getChartDataK8s(
351	        tickValues,
352	        promQueryToSummaryResponse,
353	        'Succeeded',
354	        'hour',
355	      );
356	      chartDataFailedK8s = getChartDataK8s(
357	        tickValues,
358	        promQueryToSummaryResponse,
359	        'Failed',
360	        'hour',
361	      );
362	      break;
363	    case 'day':
364	      xTickFormat = (d) => formatDate(d);
365	      domainValue.x = [startDate, endDate];
366	
367	      chartDataCancelledK8s = getChartDataK8s(
368	        tickValues,
369	        promQueryToSummaryResponse,
370	        'Cancelled',
371	        'day',
372	      );
373	      chartDataSucceededK8s = getChartDataK8s(
374	        tickValues,
375	        promQueryToSummaryResponse,
376	        'Succeeded',
377	        'day',
378	      );
379	      chartDataFailedK8s = getChartDataK8s(
380	        tickValues,
381	        promQueryToSummaryResponse,
382	        'Failed',
383	        'day',
384	      );
385	
386	      break;
387	    case 'week':
388	      xTickFormat = (d) => formatDate(d);
389	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
390	
391	      chartDataCancelledK8s = getChartDataK8s(
392	        tickValues,
393	        promQueryToSummaryResponse,
394	        'Cancelled',
395	        'week',
396	      );
397	      chartDataSucceededK8s = getChartDataK8s(
398	        tickValues,
399	        promQueryToSummaryResponse,
400	        'Succeeded',
401	        'week',
402	      );
403	      chartDataFailedK8s = getChartDataK8s(
404	        tickValues,
405	        promQueryToSummaryResponse,
406	        'Failed',
407	        'week',
408	      );
409	
410	      break;
411	    case 'month':
412	      xTickFormat = (d) => monthYear(d);
413	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
414	
415	      chartDataCancelledK8s = getChartDataK8s(
416	        tickValues,
417	        promQueryToSummaryResponse,
418	        'Cancelled',
419	        'month',
420	      );
421	      chartDataSucceededK8s = getChartDataK8s(
422	        tickValues,
423	        promQueryToSummaryResponse,
424	        'Succeeded',
425	        'month',
426	      );
427	      chartDataFailedK8s = getChartDataK8s(
428	        tickValues,
429	        promQueryToSummaryResponse,
430	        'Failed',
431	        'month',
432	      );
433	
434	      break;
435	    default:
436	      console.log('Received wrong data');
437	      break;
438	  }
439	
440	  let xAxisStyle: React.ComponentProps<typeof ChartAxis>['style'] = {
441	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
442	  };
443	  const yAxisStyle: React.ComponentProps<typeof ChartAxis>['style'] = {
444	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
445	  };
446	  if (tickValues?.length > 7) {
447	    xAxisStyle = {
448	      tickLabels: {
449	        fill: 'var(--pf-t--global--text--color--regular)',
450	        angle: 320,
451	        fontSize: 10,
452	        textAnchor: 'end',
453	        verticalAnchor: 'end',
454	      },
455	    };
456	  }
457	
458	  const colorScale = [
459	    successColor.value,
460	    failureColor.value,
461	    runningColor.value,
462	    cancelledColor.value,
463	    othersColor.value,
464	  ];
465	
466	  const colorScaleLineChart = [
467	    successColor.value,
468	    failureColor.value,
469	    cancelledColor.value,
470	    othersColor.value,
471	  ];
472	
473	  const donutDataObjK8s = React.useMemo(() => {
474	    if (totalPipelineRunsError || runSuccessRatioError) {
475	      return;
476	    }
477	    return getStatusSummary(promQueryToSummaryResponse);
478	  }, [
479	    promQueryToSummaryResponse,
480	    totalPipelineRunsError,
481	    runSuccessRatioError,
482	  ]);
483	
484	  const donutDataK8s = [
485	    {
486	      x: t('Succeeded'),
487	      y: Math.round(
488	        (100 * donutDataObjK8s?.succeeded) / donutDataObjK8s?.total,
489	      ),
490	    },
491	    {
492	      x: t('Failed'),
493	      y: Math.round((100 * donutDataObjK8s?.failed) / donutDataObjK8s?.total),
494	    },
495	
496	    {
497	      x: t('Cancelled'),
498	      y: Math.round(
499	        (100 * donutDataObjK8s?.cancelled) / donutDataObjK8s?.total,
500	      ),
501	    },
502	  ];
503	
504	  const legendData = donutDataK8s.map((data) => {
505	    return {
506	      name: `${data.x}: ${isNaN(data.y) ? 0 : data.y}%`,
507	    };
508	  });
509	
510	  React.useEffect(() => {
511	    const hasNonAbortError =
512	      (runSuccessRatioError && runSuccessRatioError.name !== 'AbortError') ||
513	      (totalPipelineRunsError && totalPipelineRunsError.name !== 'AbortError');
514	    setPipelineRunsStatusError(
515	      hasNonAbortError
516	        ? runSuccessRatioError?.message ??
517	            totalPipelineRunsError?.message ??
518	            t('Unable to load PipelineRun status')
519	        : null,
520	    );
521	  }, [runSuccessRatioError, totalPipelineRunsError]);
522	
523	  return (
524	    <>
525	      <Card
526	        className={classNames('pipeline-overview__pipelinerun-status-card', {
527	          'card-border': bordered,
528	        })}
529	      >
530	        <CardTitle className="pipeline-overview__pipelinerun-status-card__title">
531	          <span>
532	            {t('PipelineRun status')}{' '}
533	            <Popover
534	              bodyContent={
535	                <>
536	                  {t(
537	                    'PipelineRun status shows the % of PipelineRuns for various statuses like "Succeeded", "Failed" and "Cancelled".',
538	                  )}
539	                </>
540	              }
541	            >
542	              <span
543	                role="button"
544	                aria-label={t('More info')}
545	                className="ocs-getting-started-grid__tooltip-icon"
546	              >
547	                <OutlinedQuestionCircleIcon />
548	              </span>
549	            </Popover>
550	          </span>
551	        </CardTitle>
552	        <CardBody className="pipeline-overview__pipelinerun-status-card__title">
553	          {pipelineRunsStatusError ? (
554	            <Alert
555	              variant="danger"
556	              isInline
557	              title={t('Unable to load PipelineRun status')}
558	              className="pf-v6-u-mb-md"
559	            />
560	          ) : (
561	            <Grid>
562	              <GridItem xl2={4} xl={12} lg={12} md={12} sm={12}>
563	                {loadingRunSuccessRatioData ? (
564	                  <LoadingInline />
565	                ) : (
566	                  <div className="pipeline-overview__pipelinerun-status-card__donut-chart-div">
567	                    <ChartDonut
568	                      constrainToVisibleArea={true}
569	                      data={donutDataK8s}
570	                      labels={({ datum }) => `${datum.x}: ${datum.y}%`}
571	                      legendData={legendData}
572	                      colorScale={colorScale}
573	                      legendOrientation="vertical"
574	                      legendPosition="right"
575	                      padding={{
576	                        bottom: 30,
577	                        right: 140, // Adjusted to accommodate legend
578	                        top: 20,
579	                      }}
580	                      legendComponent={
581	                        <ChartLegend
582	                          data={legendData}
583	                          style={{
584	                            labels: {
585	                              fill: 'var(--pf-t--global--text--color--regular)',
586	                              fontSize: 14,
587	                            },
588	                          }}
589	                        />
590	                      }
591	                      subTitle={t('Succeeded')}
592	                      subTitleComponent={
593	                        <ChartLabel
594	                          style={{
595	                            fill: 'var(--pf-t--global--text--color--400)',
596	                            fontSize: 14,
597	                          }}
598	                        />
599	                      }
600	                      title={
601	                        typeof donutDataObjK8s !== 'undefined'
602	                          ? `${donutDataObjK8s?.succeeded}/${totalPipelineRuns}`
603	                          : ''
604	                      }
605	                      titleComponent={
606	                        <ChartLabel
607	                          style={{
608	                            fill: 'var(--pf-t--global--text--color--regular)',
609	                            fontSize: 24,
610	                          }}
611	                        />
612	                      }
613	                      width={350}
614	                    />
615	                  </div>
616	                )}
617	              </GridItem>
618	              <GridItem xl2={8} xl={12} lg={12} md={12} sm={12}>
619	                <div className="pipeline-overview__pipelinerun-status-card__bar-chart-div">
620	                  {loadingTotalPipelineRunsData ? (
621	                    <LoadingInline />
622	                  ) : (
623	                    <Chart
624	                      containerComponent={
625	                        <ChartVoronoiContainer
626	                          labels={({ datum }) => `${datum.name}: ${datum.y}%`}
627	                          constrainToVisibleArea
628	                        />
629	                      }
630	                      scale={{ x: 'time', y: 'linear' }}
631	                      domain={domainValue}
632	                      domainPadding={{ x: [30, 25] }}
633	                      height={200}
634	                      padding={{
635	                        top: 20,
636	                        bottom: 40,
637	                        right: 40,
638	                        left: 50,
639	                      }}
640	                      colorScale={colorScaleLineChart}
641	                      width={1000}
642	                    >
643	                      <ChartAxis
644	                        tickValues={tickValues}
645	                        style={xAxisStyle}
646	                        tickFormat={xTickFormat}
647	                        label={showLabel ? dayLabel : ''}
648	                      />
649	                      <ChartAxis
650	                        dependentAxis
651	                        tickFormat={(v) => `${v}%`}
652	                        style={yAxisStyle}
653	                      />
654	                      <ChartGroup>
655	                        <ChartLine data={chartDataSucceededK8s} />
656	                        <ChartLine data={chartDataFailedK8s} />
657	                        <ChartLine data={chartDataCancelledK8s} />
658	                      </ChartGroup>
659	                    </Chart>
660	                  )}
661	                </div>
662	              </GridItem>
663	            </Grid>
664	          )}
665	        </CardBody>
666	      </Card>
667	    </>
668	  );
669	};
670	
671	export default PipelineRunsStatusCardK8s;

