  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import { DomainPropType, DomainTuple } from 'victory-core';
  5	import {
  6	  Chart,
  7	  ChartAxis,
  8	  ChartDonut,
  9	  ChartGroup,
 10	  ChartLabel,
 11	  ChartLegend,
 12	  ChartLine,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts';
 15	import {
 16	  Alert,
 17	  Card,
 18	  CardBody,
 19	  CardTitle,
 20	  Grid,
 21	  GridItem,
 22	  Popover,
 23	} from '@patternfly/react-core';
 24	import { chart_color_black_200 as othersColor } from '@patternfly/react-tokens/dist/js/chart_color_black_200';
 25	import { chart_color_black_500 as cancelledColor } from '@patternfly/react-tokens/dist/js/chart_color_black_500';
 26	import { chart_color_green_400 as successColor } from '@patternfly/react-tokens/dist/js/chart_color_green_400';
 27	import { t_global_color_status_danger_default as failureColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 28	import { chart_color_blue_300 as runningColor } from '@patternfly/react-tokens/dist/js/chart_color_blue_300';
 29	import {
 30	  formatDate,
 31	  getXaxisValues,
 32	  hourformat,
 33	  parsePrometheusDuration,
 34	  monthYear,
 35	} from './dateTime';
 36	import './PipelinesOverview.scss';
 37	import { ALL_NAMESPACES_KEY } from '../../consts';
 38	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
 39	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 40	import {
 41	  usePipelineMetricsForAllNamespacePoll,
 42	  usePipelineMetricsForNamespacePoll,
 43	  usePipelineMetricsForNamespaceForPipelinePoll,
 44	} from '../pipelines-metrics/hooks';
 45	import {
 46	  MetricsQueryPrefix,
 47	  PipelineQuery,
 48	  adjustToStartOfWeek,
 49	} from '../pipelines-metrics/utils';
 50	import { getTotalPipelineRuns, isMatchingFirstTickValue } from './utils';
 51	import { LoadingInline } from '../Loading';
 52	
 53	interface PipelinesRunsStatusCardProps {
 54	  timespan?: number;
 55	  domain?: DomainPropType;
 56	  bordered?: boolean;
 57	  namespace: string;
 58	  interval: number;
 59	  parentName?: string;
 60	}
 61	
 62	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 63	
 64	const getStatusSummary = (promQueryToSummaryResponse) => {
 65	  const result = {
 66	    cancelled: 0,
 67	    failed: 0,
 68	    succeeded: 0,
 69	    total: 0,
 70	  };
 71	  promQueryToSummaryResponse?.forEach((item) => {
 72	    result.cancelled += item.cancelled;
 73	    result.failed += item.failed;
 74	    result.succeeded += item.succeeded;
 75	    result.total = result.cancelled + result.failed + result.succeeded;
 76	  });
 77	
 78	  return result;
 79	};
