 52	
 53	interface PipelinesRunsStatusCardProps {
 54	  timespan?: number;
 55	  domain?: DomainPropType;
 56	  bordered?: boolean;
 57	  namespace: string;
 58	  interval: number;
 59	  parentName?: string;
 60	}
 61	
 62	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 63	
 64	const getStatusSummary = (promQueryToSummaryResponse) => {
 65	  const result = {
 66	    cancelled: 0,
 67	    failed: 0,
 68	    succeeded: 0,
 69	    total: 0,
 70	  };
 71	  promQueryToSummaryResponse?.forEach((item) => {
 72	    result.cancelled += item.cancelled;
 73	    result.failed += item.failed;
 74	    result.succeeded += item.succeeded;
 75	    result.total = result.cancelled + result.failed + result.succeeded;
 76	  });
 77	
 78	  return result;
 79	};
 80	
 81	export const getChartDataK8s = (
 82	  tickValues: number[] | Date[],
 83	  data: any,
 84	  key: string,
 85	  type: string,
 86	): {
 87	  x: number;
 88	  y: number;
 89	  name: string;
 90	}[] => {
 91	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 92	  const k = key.toLowerCase();
 93	  const sortedTickValues = tickValues.slice().sort((a, b) => a - b);
 94	  const chartData = sortedTickValues?.map((value, index) => {
 95	    if (index === 0) {
 96	      // Ensure the first value is always 0
 97	      return {
 98	        x: value,
 99	        y: 0,
100	        name: t(key),
101	      };
102	    }
103	    const s = data?.find((d) => {
104	      const group_date = new Date(Number(d.group_value) * 1000);
105	      if (type == 'hour') {
106	        return group_date.getHours() === value;
107	      }
108	      if (type == 'week') {
109	        const adjustedGroupDate = adjustToStartOfWeek(new Date(group_date));
110	        return (
111	          adjustedGroupDate.toDateString() === new Date(value).toDateString()
112	        );
113	      }
114	      if (type == 'day') {
