130	export const getIncrementedValues = (
131	  data,
132	  tickValues: number[] | Date[],
133	  type: string,
134	) => {
135	  const originalData = JSON.parse(JSON.stringify(data));
136	  for (let i = 1; i < data.length; i++) {
137	    const prevCancelled = originalData[i - 1].cancelled;
138	    const currentCancelled = originalData[i].cancelled;
139	    data[i].cancelled =
140	      currentCancelled >= prevCancelled
141	        ? currentCancelled - prevCancelled
142	        : currentCancelled;
143	
144	    const prevFailed = originalData[i - 1].failed;
145	    const currentFailed = originalData[i].failed;
146	    data[i].failed =
147	      currentFailed >= prevFailed ? currentFailed - prevFailed : currentFailed;
148	
149	    const prevSucceeded = originalData[i - 1].succeeded;
150	    const currentSucceeded = originalData[i].succeeded;
151	    data[i].succeeded =
152	      currentSucceeded >= prevSucceeded
153	        ? currentSucceeded - prevSucceeded
154	        : currentSucceeded;
155	  }
156	
157	  const firstTickValue = tickValues[0];
158	  data.forEach((item) => {
159	    item.total = item.cancelled + item.failed + item.succeeded;
160	    const isMatch = isMatchingFirstTickValue(
161	      firstTickValue,
162	      item.group_value,
163	      type,
164	    );
165	    if (isMatch) {
166	      data[0].cancelled = 0;
167	      data[0].failed = 0;
168	      data[0].succeeded = 0;
169	    }
170	  });
171	
172	  return data;
173	};
